ALGORITHM MerkleDamgardHash
INPUT: Message M (arbitrary length), Compression Function f, Output Length n
OUTPUT: Hash digest of n bits

BEGIN
    // Step 1: Padding
    // Convert message to binary string
    message_bits = ConvertToBits(M)

    // Append single '1' bit
    message_bits = message_bits + "1"

    // Pad with '0' bits until length ≡ 448 (mod 512)
    WHILE Length(message_bits) MOD 512 ≠ 448 DO
        message_bits = message_bits + "0"
    END WHILE

    // Append original message length as 64-bit integer
    original_length = ConvertTo64Bit(Length(M))
    message_bits = message_bits + original_length

    // Step 2: Initialize Initial Vector (IV)
    num_blocks = Length(message_bits) / 512
    H0 = InitializeIV(n)  // Initial hash value

    // Step 3: Process each block
    FOR i FROM 1 TO num_blocks DO
        // Extract i-th block
        block_i = message_bits[(i-1)*512 : i*512]

        // Apply compression function
        // H_i = f(H_{i-1}, M_i)
        H_prev = H_{i-1}
        H_i = CompressionFunction(H_prev, block_i)

        // Store for next iteration
        H_{i-1} = H_i
    END FOR

    // Step 4: Output final hash
    RETURN H_{num_blocks}
END

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Simple hash simulation (in production, use OpenSSL's SHA-256)
// This demonstrates the CONCEPT of digital signatures
unsigned int simpleHash(const char* data, size_t len) {
    unsigned int hash = 5381;
    for (size_t i = 0; i < len; i++) {
        hash = ((hash << 5) + hash) + data[i];  // hash * 33 + data[i]
    }
    return hash;
}

// Simulated private key (in real system, use RSA/ECDSA)
#define PRIVATE_KEY 0xDEADBEEF
#define PUBLIC_KEY  0xCAFEBABE

typedef struct {
    const char* message;
    unsigned int hash;
    unsigned int signature;
} SignedDocument;

// Simulate signing: hash(message) then encrypt with private key
// In reality: signature = RSA_Sign(hash, privateKey)
SignedDocument signDocument(const char* message) {
    SignedDocument doc;
    doc.message = message;

    // Step 1: Compute hash of message
    doc.hash = simpleHash(message, strlen(message));

    // Step 2: "Encrypt" hash with private key (signature simulation)
    // Real implementation: Use RSA/ECDSA with private key
    doc.signature = doc.hash ^ PRIVATE_KEY;  // XOR as simulation

    return doc;
}

// Simulate verification: decrypt signature, compare with hash
// Returns 1 if valid, 0 if invalid
int verifySignature(const SignedDocument* doc) {
    // Step 1: Recompute hash of received message
    unsigned int computedHash = simpleHash(doc->message, strlen(doc->message));

    // Step 2: "Decrypt" signature to get original hash
    unsigned int decryptedSignature = doc->signature ^ PRIVATE_KEY;

    // Step 3: Compare
    return (computedHash == decryptedSignature);
}

void printDocument(const char* label, const SignedDocument* doc) {
    printf("%s\n", label);
    printf("  Message: \"%s\"\n", doc->message);
    printf("  Hash:    0x%08X\n", doc->hash);
    printf("  Signature: 0x%08X\n", doc->signature);
}

int main() {
    printf("=== Digital Signature Simulation ===\n\n");

    // Sender: Sign a message
    const char* originalMessage = "Transfer $1000 to Account 12345";
    SignedDocument signedDoc = signDocument(originalMessage);

    printDocument("ORIGINAL DOCUMENT:", &signedDoc);

    // Verification: Check signature
    int valid = verifySignature(&signedDoc);
    printf("\nVerification Result: %s\n", valid ? "VALID - Signature matches" : "INVALID");

    // Simulate attacker tampering with message
    printf("\n--- ATTACK SIMULATION ---\n");

    // Attacker changes message but doesn't know private key
    signedDoc.message = "Transfer $9999 to Account 12345";  // Tampered!

    printDocument("TAMPERED DOCUMENT:", &signedDoc);

    // Verification fails because hash doesn't match signature
    valid = verifySignature(&signedDoc);
    printf("\nVerification Result: %s\n", valid ? "VALID" : "INVALID - Signature mismatch detected!");

    printf("\n=== Key Concept ===\n");
    printf("1. Hash the message (SHA-256 etc.)\n");
    printf("2. Sign the hash with private key (RSA/ECDSA)\n");
    printf("3. Receiver verifies by: recompute hash, decrypt signature, compare\n");
    printf("4. If message changes, hash changes, signature verification fails\n");

    return 0;
}
